691		fsckOut, err := cmd.CombinedOutput()
692		switch {
693		case err != nil:
694			checks = append(checks, Check{Name: "git fsck --full", OK: false, Detail: fmt.Sprintf("%v\n%s", err, fsckOut)})
695		case fsckHasError(fsckOut):
696			// Belt-and-braces against a hypothetical git version that prints
697			// "error:" / "fatal:" lines but exits zero. Match line prefixes
698			// rather than a substring so a branch or path containing "error"
699			// in a benign dangling/warning line doesn't trip the check.
700			checks = append(checks, Check{Name: "git fsck --full", OK: false, Detail: strings.TrimSpace(string(fsckOut))})
701		default:
702			checks = append(checks, Check{Name: "git fsck --full", OK: true, Detail: "clean"})
703		}
704		return checks
705	}
706	
707	// fsckHasError reports whether git-fsck output contains a line that
708	// signals a real problem. We match (case-insensitively) any line whose
709	// first token starts with "error" or "fatal" — covering "error:",
710	// "fatal:", and the rare "errorInX:" variants — plus the
711	// "missing <type> <sha>" / "broken link" / "bad <thing>" object reports
712	// emitted by older git. Dangling and warning lines are intentionally
713	// ignored.
714	//
715	// Splits on raw newlines rather than using bufio.Scanner so a single
716	// very long line (some fsck reports include long paths) is not
717	// silently truncated at the scanner's 64 KiB default.
718	func fsckHasError(out []byte) bool {
719		for _, raw := range bytes.Split(out, []byte("\n")) {
720			line := strings.TrimSpace(string(raw))
721			if line == "" {
722				continue
723			}
724			lower := strings.ToLower(line)
725			if strings.HasPrefix(lower, "error") || strings.HasPrefix(lower, "fatal") {
726				return true
727			}
728			if strings.HasPrefix(lower, "missing ") || strings.HasPrefix(lower, "broken link") || strings.HasPrefix(lower, "bad ") {
729				return true
730			}
731		}
732		return false
733	}
734	
735	const (
736		originNotesRef       = "refs/notes/sha1-origin"
737		attestationTagPrefix = "refs/tags/converted/"
738	)
739	
740	// --sign-mode values. SignModeNone (and the empty string) sign nothing;
741	// SignModeTips mints one signed attestation tag per branch tip. The set
742	// is deliberately small and forward-compatible: an "all" mode that signs
743	// every commit/tag could be added without changing the flag's shape.
744	const (
745		SignModeNone = "none"
746		SignModeTips = "tips"
747	)
748	
749	// foreignPullRefPrefixes are the server-internal pull/merge-request
750	// namespaces that hold code proposed from forks and other branches —
751	// content foreign to the repository's own history until merged. They are
752	// excluded from --all-refs by default: the converted repo is usually
753	// mirrored onward with `git push --mirror`, and a destination forge may
754	// surface these refs as ordinary refs, republishing unreviewed code as if
755	// it were part of the repo. --include-pull-refs opts back in.
756	var foreignPullRefPrefixes = []string{
757		"refs/pull/",           // GitHub, Gitea, Forgejo
758		"refs/pull-requests/",  // Bitbucket Server / Data Center
759		"refs/merge-requests/", // GitLab
760	}
761	
762	// effectiveExcludePrefixes combines the user's --exclude-ref-prefix values
763	// with the default pull/merge-request exclusions. The latter only apply
764	// under --all-refs (the namespaces are out of scope otherwise) and only
765	// when the user did not pass --include-pull-refs.
766	func effectiveExcludePrefixes(userPrefixes []string, allRefs, includePullRefs bool) []string {
767		out := append([]string(nil), userPrefixes...)
768		if allRefs && !includePullRefs {
769			out = append(out, foreignPullRefPrefixes...)
770		}
771		return out
772	}
773	
774	// countForeignPullRefs reports how many source refs fall under a
775	// pull/merge-request namespace, so the run can tell the user exactly how
776	// many refs the default exclusion dropped rather than silently omitting
777	// them from an --all-refs conversion.
778	func countForeignPullRefs(refs map[plumbing.ReferenceName]plumbing.Hash) int {
779		n := 0
780		for name := range refs {
781			for _, p := range foreignPullRefPrefixes {
782				if strings.HasPrefix(string(name), p) {
783					n++
784					break
785				}
786			}
787		}
788		return n
789	}
790	
791	// protectedExcludePrefixes returns the subset of prefixes that, under
792	// planner.IsRefExcluded's string-prefix semantics, would knock out at
793	// least one branch or tag. A prefix matches a branch if either side
794	// is a string-prefix of the other against "refs/heads/" (and likewise
795	// for "refs/tags/"). That covers:
796	//
797	//   - bare "" (excludes every ref)
798	//   - "refs/" or "refs/h", "refs/heads/" (whole branch namespace)
799	//   - "refs/heads/feature/" (some branches)
800	//   - "refs/tags/" and any narrower suffix
801	//
802	// Returned in input order, with duplicates removed, so the error
803	// message shows the user exactly which flag values to drop.
804	func protectedExcludePrefixes(prefixes []string) []string {
805		protected := []string{"refs/heads/", "refs/tags/"}
806		var bad []string
807		seen := map[string]struct{}{}
808		for _, raw := range prefixes {
809			p := strings.TrimSpace(raw)
810			if _, dup := seen[p]; dup {
811				continue
812			}
813			for _, prot := range protected {
814				if strings.HasPrefix(p, prot) || strings.HasPrefix(prot, p) {
815					bad = append(bad, raw)
816					seen[p] = struct{}{}
817					break
818				}
819			}

