export const meta = {
  name: 'review-convert-sha256',
  description: 'Deep review of the convert-sha256 PR: fan out across dimensions, adversarially verify each finding against the code',
  phases: [
    { title: 'Review' },
    { title: 'Verify' },
  ],
}

const REPO = '/Users/nodo/work/entire/git-sync'
const CORE = `${REPO}/cmd/git-sync/internal/sha256convert/sha256convert.go`
const CMD = `${REPO}/cmd/git-sync/convert_sha256.go`
const CORE_TEST = `${REPO}/cmd/git-sync/internal/sha256convert/sha256convert_test.go`
const CMD_TEST = `${REPO}/cmd/git-sync/convert_sha256_test.go`
const DOCS = `${REPO}/docs/convert-sha256.md`
const README = `${REPO}/README.md`

const FINDINGS_SCHEMA = {
  type: 'object',
  properties: {
    summary: { type: 'string', description: 'One-paragraph assessment of this dimension overall' },
    findings: {
      type: 'array',
      items: {
        type: 'object',
        properties: {
          severity: { type: 'string', enum: ['critical', 'high', 'medium', 'low', 'nit'] },
          title: { type: 'string' },
          file: { type: 'string' },
          line: { type: 'string', description: 'line number or range, e.g. "865-941"' },
          evidence: { type: 'string', description: 'quote the exact code/text that is the problem' },
          explanation: { type: 'string', description: 'why this is a problem; concrete failure scenario if any' },
          suggested_fix: { type: 'string' },
          confidence: { type: 'string', enum: ['high', 'medium', 'low'] },
        },
        required: ['severity', 'title', 'file', 'line', 'evidence', 'explanation', 'confidence'],
      },
    },
  },
  required: ['summary', 'findings'],
}

const VERDICT_SCHEMA = {
  type: 'object',
  properties: {
    real: { type: 'boolean', description: 'true if the finding is a genuine, reproducible problem in the current code' },
    severity_adjusted: { type: 'string', enum: ['critical', 'high', 'medium', 'low', 'nit', 'not-a-bug'] },
    reasoning: { type: 'string', description: 'cite the actual current code you read; explain why real or not' },
  },
  required: ['real', 'severity_adjusted', 'reasoning'],
}

const preamble = `You are reviewing an OPEN pull request (#66) that adds a \`git-sync convert-sha256\` subcommand: a one-off SHA1 -> SHA256 git repository conversion. It fetches a pack over smart HTTP from a SHA1 source, walks every reachable object via a two-pass topological DFS (discovery then translation), and writes a fresh SHA256 bare repo where every tree/commit/tag reference is re-encoded under SHA256. Optional features: --sign-mode tips (signed attestation tags per branch), --check (post-conversion fsck/config/ref verification), refs/notes/sha1-origin (reverse lookup), --write-mapping TSV, inline rewriting of SHA1 hashes in commit/tag messages, ref-scope policy (--all-refs / --exclude-ref-prefix / --include-pull-refs).

Key files:
- Core: ${CORE} (~1803 lines)
- CLI: ${CMD}
- Core tests: ${CORE_TEST}
- CLI tests: ${CMD_TEST}
- Docs: ${DOCS}
- README diff: ${README}

Ground EVERY finding in the actual current code — open the files and quote exact lines. Do not invent problems. Report only genuine issues; an empty findings list is a valid, good answer. Prefer high-confidence correctness bugs (wrong output, corruption, data loss, crashes, security) over style. For each finding give file, line range, the exact offending code as evidence, a concrete failure scenario, and a fix.`

const DIMENSIONS = [
  {
    key: 'object-encoding',
    prompt: `${preamble}

DIMENSION: Object re-encoding correctness — the heart of the tool.
Scrutinize how trees, commits, and tags are re-encoded from SHA1 to SHA256. Look at the translation DFS, memoization (sha1->sha256 map), topological ordering, the inProgress cycle guard, and how loose objects are written (it uses go-git SetEncodedObject after dropping a hand-rolled writer). Verify:
- Tree entry re-encoding preserves modes, filenames, ordering; gitlinks (mode 160000 / submodules) handled correctly (fail-fast in discovery).
- Commit re-encoding rewrites tree + all parents, preserves author/committer/message/encoding headers, and strips GPG signatures (gpgsig header) correctly without corrupting other headers.
- Tag re-encoding rewrites the target object hash and type, strips signature.
- The sha256(content) on-disk invariant actually holds; no SHA1 leakage into stored object content.
- Idempotency / determinism of hash mapping.
- Edge cases: empty tree, root commit (no parent), octopus merges, annotated tag chains (tag->tag), commits with non-UTF8 / custom encoding header, signed commits where signature is mid-header.
Read the code carefully and report genuine correctness risks.`,
  },
  {
    key: 'discovery-refpolicy',
    prompt: `${preamble}

DIMENSION: Reachability discovery, ref scope policy, context cancellation.
Examine discoverReachable (iterative DFS), and the ref-scope logic: which refs are converted (branches+tags always), --all-refs, --exclude-ref-prefix, --include-pull-refs, protectedExcludePrefixes (rejecting prefixes that would drop a branch/tag), effectiveExcludePrefixes, foreignPullRefPrefixes, HEAD resolution + fallback when source omits HEAD, and refusing source refs that collide with side outputs (refs/notes/sha1-origin, refs/tags/converted/*). Verify:
- ctx.Err() is actually checked during discovery (a prior review flagged it was not).
- No reachable object is missed (tree recursion, commit tree+parents, tag targets, gitlinks not followed out of repo).
- The always-convert-branches-and-tags invariant cannot be violated by any flag combination.
- Collisions between source refs and the tool's own side outputs are detected.
- Prefix matching semantics (string prefix) don't have off-by-one / partial-segment bugs (e.g. refs/heads/feat matching refs/heads/feature).
Report genuine issues.`,
  },
  {
    key: 'messages-notes-mapping',
    prompt: `${preamble}

DIMENSION: Commit/tag message hash rewriting, origin notes, mapping file, credential redaction.
Examine: detection of SHA1 hash references (full + abbreviated) in commit/tag messages, the uniqueness/ambiguity verdict for abbreviated prefixes (must be stable regardless of translation progress — that's why discovery runs first), replacement with SHA256, the --no-rewrite-messages path; refs/notes/sha1-origin construction (one note per commit mapping sha256->original sha1) and --no-origin-notes; the --write-mapping TSV format; and redaction of credentials from the source URL in output/tags/notes (a recent commit added this). Verify:
- Abbreviated-prefix matching can't corrupt messages (e.g. matching a hex substring inside a word, or a 7-char prefix that is also a normal English/hex token); word-boundary handling.
- Ambiguous prefixes are left alone, not mis-rewritten.
- The notes ref is well-formed (proper note blob + tree + commit), resolvable by 'git notes --ref=sha1-origin show <sha256>'.
- Mapping TSV has no quoting/escaping issues.
- Credentials in source URL (user:pass@host) are fully redacted everywhere they could leak (stdout, JSON, tag message, notes, mapping).
Report genuine issues.`,
  },
  {
    key: 'signing-check',
    prompt: `${preamble}

DIMENSION: Signing (--sign-mode) and --check verification.
Examine: SignMode validation (none/tips), signBranchTips shelling out to 'git tag -s converted/<branch> <tip>' (and -u <key> for --sign-key), the attestation tag message/content, error handling if signing fails partway (PR claims partial results are printed), and the runCheck logic: extensions.objectformat=sha256 parse, HEAD resolves, all refs resolve to objects, git fsck --full + fsckHasError prefix matching. Verify:
- SignMode is actually validated; an invalid value errors clearly rather than silently signing nothing.
- git tag invocation is safe against branch names with shell-special or ref-special characters; no shell injection (is it exec with args or via shell?).
- Branch names that aren't valid tag name components (e.g. containing characters illegal in tag refs) are handled.
- fsckHasError won't false-negative on real corruption or false-positive on benign dangling/warning lines.
- config parsing in --check is section-aware (a recent commit claims this) and robust.
Report genuine issues.`,
  },
  {
    key: 'cli-io-lifecycle',
    prompt: `${preamble}

DIMENSION: CLI layer, I/O, resource lifecycle, concurrency.
Examine ${CMD} (arg resolution resolveConvertSHA256Args, flag wiring, partial-result printing on error, JSON output) and in the core: the --progress ticker (atomic counters, goroutine lifecycle, TTY detection, does it stop cleanly / no leak / no race), temp SHA1 store creation + cleanup (--keep-source-objects), file/handle closing (deferred Close error handling), and overall error wrapping. Verify:
- resolveConvertSHA256Args handles all flag/positional combinations without misassignment (the comment claims --source-url <url> <dir> works).
- The progress goroutine cannot race translation (PR claims atomics) and is always stopped.
- Temp dirs are always cleaned up on every error path (except --keep-source-objects); no half-written target left in a confusing state.
- Deferred Close() errors on the written bare repo / loose objects are not silently swallowed in a way that hides a failed write.
Report genuine issues.`,
  },
  {
    key: 'tests',
    prompt: `${preamble}

DIMENSION: Test adequacy and quality.
Read both test files. Assess what is and isn't covered. The PR claims coverage of: blobs/trees/commits/tags incl. signed commit + signed annotated tag, idempotency, on-disk sha256(content) invariant for every loose object, message rewriting (ancestor + cross-branch + ambiguous + skip), origin notes, mapping file, submodule fail-fast in discovery, CLI arg resolution, and a gated git-http-backend e2e incl. signing. Verify these claims against the actual test code and identify meaningful GAPS: untested edge cases, paths with no coverage, assertions that are too weak (e.g. asserting no error but not asserting output content), brittleness (timing, ordering, network), or tests that could pass even if the feature were broken. Be specific with test function names and line numbers. Do NOT propose adding tests for trivial things; focus on coverage gaps that matter for correctness confidence.`,
  },
  {
    key: 'docs',
    prompt: `${preamble}

DIMENSION: Documentation accuracy and completeness.
Carefully compare ${DOCS} and the README diff against the ACTUAL implementation in ${CORE} and ${CMD}. For every claim, flag, default, and example in the docs, check it matches the code. Look specifically for:
- Stale claims (e.g. the docs previously said go-git hardcodes SHA1 / a hand-rolled loose writer is used — verify the docs now match the SetEncodedObject reality).
- Flag names/defaults that drift from the code (--sign-mode none|tips default none, --sign-key, --all-refs, --exclude-ref-prefix, --include-pull-refs, --no-rewrite-messages, --no-origin-notes, --check, --progress, --write-mapping, --keep-source-objects).
- Example command output that no longer matches actual output format.
- Sharp edges that are in the code but NOT documented (signatures stripped, submodule fail-fast, foreign pull refs excluded, credential redaction, message rewriting caveats), or documented but not implemented.
- Recovery / operational guidance correctness (e.g. 'git notes --ref=sha1-origin show <sha256>' actually works as written).
Give a clear verdict on doc quality and list concrete inaccuracies with line numbers in the docs.`,
  },
]

phase('Review')
const results = await pipeline(
  DIMENSIONS,
  d => agent(d.prompt, { label: `review:${d.key}`, phase: 'Review', schema: FINDINGS_SCHEMA }),
  (review, d) => parallel((review.findings || [])
    .filter(f => ['critical', 'high', 'medium'].includes(f.severity))
    .map(f => () =>
      agent(`${preamble}

ADVERSARIAL VERIFICATION. Another reviewer claims the following issue in dimension "${d.key}". Open the cited file at the cited lines, read the surrounding code, and decide whether it is a GENUINE, reproducible problem in the CURRENT code (not an earlier revision). Default to real=false if you cannot concretely confirm it by reading the code. Be skeptical: many plausible-sounding findings dissolve on inspection.

CLAIM:
- title: ${f.title}
- severity: ${f.severity}
- file: ${f.file}
- line: ${f.line}
- evidence: ${f.evidence}
- explanation: ${f.explanation}
- suggested_fix: ${f.suggested_fix || '(none given)'}

Verify against the actual code now.`,
        { label: `verify:${d.key}:${(f.title || '').slice(0, 30)}`, phase: 'Verify', schema: VERDICT_SCHEMA })
        .then(v => ({ ...f, dimension: d.key, verdict: v }))
        .catch(() => ({ ...f, dimension: d.key, verdict: { real: false, severity_adjusted: 'not-a-bug', reasoning: 'verification errored' } }))
    )),
)

// results is [reviewObj-or-verifiedFindings...] — pipeline returns the LAST stage output per item.
// Last stage returns the array of verified findings per dimension. Stitch with the review summaries.
const verifiedByDim = results.map(r => Array.isArray(r) ? r : []).flat().filter(Boolean)
const summaries = await parallel(DIMENSIONS.map((d, i) => async () => {
  // re-fetch the review summary is not stored; instead capture low/nit findings too via a lightweight note
  return null
}))

const confirmed = verifiedByDim.filter(f => f.verdict && f.verdict.real)
const rejected = verifiedByDim.filter(f => !(f.verdict && f.verdict.real))

return {
  confirmed_findings: confirmed,
  rejected_claims: rejected.map(f => ({ dimension: f.dimension, title: f.title, severity: f.severity, why_rejected: f.verdict?.reasoning })),
  counts: {
    confirmed: confirmed.length,
    rejected: rejected.length,
    by_severity: confirmed.reduce((a, f) => { const s = f.verdict.severity_adjusted; a[s] = (a[s] || 0) + 1; return a }, {}),
  },
}

