1153	func (t *translator) translate(sha1 plumbing.Hash) (plumbing.Hash, error) {
1154		// Cheap per-object cancellation check so Ctrl-C during a long
1155		// conversion (kernel-scale: ~10M objects) returns promptly rather
1156		// than running the whole DFS to completion.
1157		if err := t.ctx.Err(); err != nil {
1158			return plumbing.ZeroHash, fmt.Errorf("translate %s: %w", sha1, err)
1159		}
1160		if newH, ok := t.mapping[sha1]; ok {
1161			return newH, nil
1162		}
1163		if _, busy := t.inProgress[sha1]; busy {
1164			// Real Git histories cannot form cycles via parent, tree, or
1165			// tag-target edges (those are a DAG by construction), and
1166			// SHA1 message-reference cycles are cryptographically
1167			// infeasible (each commit's hash depends on its content,
1168			// including any hash it embeds). A trip here would mean an
1169			// unexpected graph shape; surface it instead of overflowing
1170			// the stack.
1171			return plumbing.ZeroHash, fmt.Errorf("translation cycle detected at %s", sha1)
1172		}
1173		t.inProgress[sha1] = struct{}{}
1174		defer delete(t.inProgress, sha1)
1175	
1176		obj, err := t.src.EncodedObject(plumbing.AnyObject, sha1)
1177		if err != nil {
1178			return plumbing.ZeroHash, fmt.Errorf("lookup %s: %w", sha1, err)
1179		}
1180		switch obj.Type() { //nolint:exhaustive // OFSDelta/REFDelta/AnyObject/InvalidObject cannot reach a resolved storage.
1181		case plumbing.BlobObject:
1182			return t.translateBlob(sha1, obj)
1183		case plumbing.TreeObject:
1184			return t.translateTree(sha1, obj)
1185		case plumbing.CommitObject:
1186			return t.translateCommit(sha1, obj)
1187		case plumbing.TagObject:
1188			return t.translateTag(sha1, obj)
1189		default:
1190			return plumbing.ZeroHash, fmt.Errorf("unexpected object type %v for %s", obj.Type(), sha1)
1191		}
1192	}
