1194	func (t *translator) translateBlob(sha1 plumbing.Hash, src plumbing.EncodedObject) (plumbing.Hash, error) {
1195		r, err := src.Reader()
1196		if err != nil {
1197			return plumbing.ZeroHash, fmt.Errorf("blob reader: %w", err)
1198		}
1199		defer r.Close()
1200		body, err := io.ReadAll(r)
1201		if err != nil {
1202			return plumbing.ZeroHash, fmt.Errorf("blob read: %w", err)
1203		}
1204		newHash, err := t.storeBlob(body)
1205		if err != nil {
1206			return plumbing.ZeroHash, fmt.Errorf("blob store: %w", err)
1207		}
1208		t.mapping[sha1] = newHash
1209		t.blobs.Add(1)
1210		return newHash, nil
1211	}
