1213	func (t *translator) translateTree(sha1 plumbing.Hash, src plumbing.EncodedObject) (plumbing.Hash, error) {
1214		tree := &object.Tree{}
1215		if err := tree.Decode(src); err != nil {
1216			return plumbing.ZeroHash, fmt.Errorf("decode tree %s: %w", sha1, err)
