1221				// submodule gitlink up-front. Keep this as a defensive
1222				// guard so the rewrite path never silently produces a
1223				// SHA256 tree whose gitlink points at a hash the
1224				// .gitmodules upstream repo cannot resolve.
1225				return plumbing.ZeroHash, fmt.Errorf(
1226					"tree %s contains submodule gitlink %q at %s; convert-sha256 refuses to rewrite submodule pointers",
1227					sha1, entry.Name, entry.Hash)
