1244	func (t *translator) translateCommit(sha1 plumbing.Hash, src plumbing.EncodedObject) (plumbing.Hash, error) {
1245		c := &object.Commit{}
1246		if err := c.Decode(src); err != nil {
1247			return plumbing.ZeroHash, fmt.Errorf("decode commit %s: %w", sha1, err)
1248		}
1249		newTree, err := t.translate(c.TreeHash)
1250		if err != nil {
1251			return plumbing.ZeroHash, fmt.Errorf("commit %s tree: %w", sha1, err)
1252		}
1253		c.TreeHash = newTree
1254		for i, p := range c.ParentHashes {
1255			newP, err := t.translate(p)
1256			if err != nil {
1257				return plumbing.ZeroHash, fmt.Errorf("commit %s parent %s: %w", sha1, p, err)
1258			}
1259			c.ParentHashes[i] = newP
1260		}
1261		if t.rewriteMessages {
1262			// Translate every in-scope SHA1 mentioned in this commit's
1263			// message before rewriting it. This makes the message-reference
1264			// edge part of the translation DFS, so the mapping contains
1265			// each referenced object by the time we substitute. Without
1266			// it, sibling-branch references (cherry-picks, etc.) would
1267			// only resolve when ref iteration happened to process the
1268			// referenced commit's branch first.
1269			for _, ref := range t.extractMessageReferences(c.Message) {
1270				if _, err := t.translate(ref); err != nil {
1271					return plumbing.ZeroHash, fmt.Errorf("commit %s message ref %s: %w", sha1, ref, err)
1272				}
1273			}
1274			if rewritten, n := t.rewriteHashesInMessage(c.Message); n > 0 {
1275				c.Message = rewritten
1276				t.messageRewrites += n
1277			}
1278		}
1279		// A commit can carry both Signature (SHA1 form, "gpgsig") and
1280		// SignatureSHA256 ("gpgsig-sha256") in a transitional dual-hash
1281		// repo, but they encode the same logical signature. Strip both
1282		// fields if present, count once.
1283		if c.Signature != "" || c.SignatureSHA256 != "" {
1284			c.Signature = ""
1285			c.SignatureSHA256 = ""
1286			t.signaturesStripped++
1287		}
1288		// "mergetag" extra headers embed a copy of a signed annotated tag with
1289		// its own signature. Drop them too — they reference the pre-rewrite
1290		// commit/tag content and cannot be re-signed here.
1291		if len(c.ExtraHeaders) > 0 {
1292			filtered := c.ExtraHeaders[:0]
1293			for _, h := range c.ExtraHeaders {
1294				if h.Key == "mergetag" {
1295					t.signaturesStripped++
1296					continue
1297				}
1298				filtered = append(filtered, h)
1299			}
1300			c.ExtraHeaders = filtered
1301		}
1302		newHash, err := t.store(c.Encode)
1303		if err != nil {
1304			return plumbing.ZeroHash, fmt.Errorf("store commit %s: %w", sha1, err)
1305		}
1306		t.mapping[sha1] = newHash
1307		t.commits = append(t.commits, sha1)
1308		t.commitsCount.Add(1)
1309		return newHash, nil
1310	}
