1312	func (t *translator) translateTag(sha1 plumbing.Hash, src plumbing.EncodedObject) (plumbing.Hash, error) {
1313		tag := &object.Tag{}
1314		if err := tag.Decode(src); err != nil {
1315			return plumbing.ZeroHash, fmt.Errorf("decode tag %s: %w", sha1, err)
1316		}
1317		newTarget, err := t.translate(tag.Target)
1318		if err != nil {
1319			return plumbing.ZeroHash, fmt.Errorf("tag %s target: %w", sha1, err)
