1323			// Same as translateCommit: translate every in-scope message
1324			// reference before rewriting, so cross-branch references
1325			// always resolve regardless of ref iteration order.
1326			for _, ref := range t.extractMessageReferences(tag.Message) {
1327				if _, err := t.translate(ref); err != nil {
1328					return plumbing.ZeroHash, fmt.Errorf("tag %s message ref %s: %w", sha1, ref, err)
1329				}
1330			}
1331			if rewritten, n := t.rewriteHashesInMessage(tag.Message); n > 0 {
1332				tag.Message = rewritten
1333				t.messageRewrites += n
1334			}
1335		}
