1337		// of the same logical signature in a transitional dual-hash repo.
1338		if tag.Signature != "" || tag.SignatureSHA256 != "" {
1339			tag.Signature = ""
1340			tag.SignatureSHA256 = ""
1341			t.signaturesStripped++
1342		}
1343		newHash, err := t.store(tag.Encode)
1344		if err != nil {
1345			return plumbing.ZeroHash, fmt.Errorf("store tag %s: %w", sha1, err)
