1352	// store encodes an object into a fresh EncodedObject bound to the target
1353	// store's SHA256 hasher and persists it as a loose object, returning the
1354	// new SHA256 hash. Building the object via dst.NewEncodedObject is what
1355	// guarantees the returned hash and the on-disk filename are both computed
1356	// under SHA256: NewEncodedObject binds the object to the store's object
1357	// format, and SetEncodedObject writes (and returns) it under that format.
1358	//
1359	// This path could not be used on go-git v6 alpha.3 — its objfile.Writer
1360	// hardcoded SHA1, so SetEncodedObject placed every translated object at a
1361	// SHA1-derived path even on a SHA256 store. alpha.4 derives the hash
1362	// format from the store config (go-git commit 5cab3a7), so the manual
1363	// loose-object writer this code used to carry is no longer needed.
1364	//
1365	// go-git's loose writer is atomic (tempfile + rename) and idempotent on
1366	// duplicate hashes (it lstats the destination and drops the temp file if
1367	// it already exists); duplicate source objects never reach here anyway,
1368	// since translate() memoizes through t.mapping before encoding.
1369	func (t *translator) store(encode func(plumbing.EncodedObject) error) (plumbing.Hash, error) {
1370		obj := t.dst.NewEncodedObject()
1371		if err := encode(obj); err != nil {
1372			return plumbing.ZeroHash, err
1373		}
1374		h, err := t.dst.SetEncodedObject(obj)
1375		if err != nil {
1376			return plumbing.ZeroHash, fmt.Errorf("set encoded object: %w", err)
1377		}
1378		return h, nil
1379	}
