1386			o.SetType(plumbing.BlobObject)
1387			o.SetSize(int64(len(content)))
1388			w, err := o.Writer()
1389			if err != nil {
1390				return fmt.Errorf("blob writer: %w", err)
1391			}
1392			if _, err := w.Write(content); err != nil {
1393				_ = w.Close()
1394				return fmt.Errorf("write blob content: %w", err)
1395			}
1396			if err := w.Close(); err != nil {
1397				return fmt.Errorf("close blob writer: %w", err)
1398			}
1399			return nil
1400		})
