1403	// hashPattern matches hex runs that could be a git object hash. Git's
1404	// default abbreviation is 7 chars; 40 is a full SHA1. Case-insensitive
1405	// so messages that paste an uppercase or mixed-case hash (e.g. from
1406	// some commit graph viewers) still resolve — the lookup canonicalizes
1407	// to lowercase before checking the reachable set. We only rewrite a
1408	// match if the prefix uniquely identifies a commit or tag in the
1409	// reachable set, so false positives on incidental hex strings are
1410	// essentially impossible (a random hex would have to collide with a
1411	// real source SHA1).
1412	var hashPattern = regexp.MustCompile(`(?i)\b[0-9a-f]{7,40}\b`)
1413	
1414	// matchResult is the 3-state outcome of resolving a hex prefix in a
1415	// commit/tag message against the reachable set. We distinguish
1416	// "ambiguous" from "no match" so the caller can warn the user about
1417	// prefixes that *could* be rewritten if they were a couple of chars
1418	// longer.
1419	type matchResult int
1420	
1421	const (
1422		matchNone matchResult = iota
1423		matchUnique
1424		matchAmbiguous
1425	)
1426	
1427	// rewriteHashesInMessage scans msg for short and full SHA1 hashes,
1428	// replacing any that uniquely identify a commit or tag in t.reachable
1429	// with the corresponding full SHA256 hex from t.mapping. Returns the
1430	// rewritten message and the number of substitutions made. Ambiguous
1431	// prefixes are recorded in t.ambiguousMessageRefs so the caller can
1432	// surface a warning at the end of the run.
1433	//
1434	// Uniqueness is decided against t.reachable rather than t.mapping so
1435	// that abbreviated prefixes get the same verdict during translation as
1436	// they would after every object has been translated — the answer cannot
1437	// flip depending on what has been processed so far.
1438	//
1439	// Performance: the abbreviated-hash path scans the reachable set
1440	// linearly for each match. Fine for repos up to ~100k commits; slower
1441	// past that. If this ever matters, build a sorted-prefix index over
1442	// reachable SHA1 hex strings once and binary-search.
1443	func (t *translator) rewriteHashesInMessage(msg string) (string, int) {
1444		count := 0
1445		out := hashPattern.ReplaceAllStringFunc(msg, func(s string) string {
1446			sha1, result := t.resolveMessageRef(s)
1447			switch result {
1448			case matchNone:
1449				return s
1450			case matchAmbiguous:
1451				t.ambiguousMessageRefs[s] = struct{}{}
1452				return s
1453			case matchUnique:
1454				newHash, ok := t.mapping[sha1]
1455				if !ok {
1456					// The reachable set says this SHA1 is in scope, but
1457					// the translation DFS hasn't placed it yet. Shouldn't
1458					// happen because translateCommit/translateTag add
1459					// message-reference edges before encoding — leave the
1460					// hex untouched if it somehow does.
1461					return s
1462				}
1463				count++
1464				return newHash.String()
1465			default:
1466				return s
1467			}
1468		})
1469		return out, count
1470	}
1471	
1472	// resolveMessageRef classifies a hex prefix against the reachable set.
1473	// Returns matchUnique with the resolved SHA1 when exactly one commit
1474	// or tag in scope matches; matchAmbiguous when more than one does;
1475	// matchNone otherwise (no match, or the match is a blob/tree — those
1476	// are filtered so incidental hex collisions on content hashes aren't
1477	// rewritten).
1478	// resolveCacheEntry holds a memoized (Hash, matchResult) pair from
1479	// resolveMessageRef. Stored in t.resolveCache keyed by lowercased prefix.
1480	type resolveCacheEntry struct {
1481		hash   plumbing.Hash
1482		result matchResult
1483	}
1484	
1485	func (t *translator) resolveMessageRef(prefix string) (plumbing.Hash, matchResult) {
1486		// Canonicalize to lowercase: hashPattern is case-insensitive so
1487		// the caller can match `ABCD1234` in a message, but reachable
1488		// keys and plumbing.Hash.String() are always lowercase hex.
1489		prefix = strings.ToLower(prefix)
1490		if cached, ok := t.resolveCache[prefix]; ok {
1491			return cached.hash, cached.result
1492		}
1493		hash, result := t.resolveMessageRefUncached(prefix)
1494		t.resolveCache[prefix] = resolveCacheEntry{hash: hash, result: result}
1495		return hash, result
1496	}
1497	
1498	func (t *translator) resolveMessageRefUncached(prefix string) (plumbing.Hash, matchResult) {
1499		if len(prefix) == 40 {
1500			sha1, ok := plumbing.FromHex(prefix)
1501			if !ok {
1502				return plumbing.ZeroHash, matchNone
1503			}
1504			typ, in := t.reachable[sha1]
1505			if !in {
1506				return plumbing.ZeroHash, matchNone
1507			}
1508			if typ != plumbing.CommitObject && typ != plumbing.TagObject {
1509				return plumbing.ZeroHash, matchNone
1510			}
1511			return sha1, matchUnique
1512		}
1513		var match plumbing.Hash
1514		matches := 0
1515		for sha1, typ := range t.reachable {
1516			if typ != plumbing.CommitObject && typ != plumbing.TagObject {
1517				continue
1518			}
1519			if strings.HasPrefix(sha1.String(), prefix) {
1520				matches++
1521				if matches > 1 {
1522					return plumbing.ZeroHash, matchAmbiguous
1523				}
1524				match = sha1
1525			}
1526		}
1527		if matches == 1 {
1528			return match, matchUnique
1529		}
1530		return plumbing.ZeroHash, matchNone
1531	}
1532	
1533	// extractMessageReferences returns the unique commit/tag SHA1s mentioned
1534	// by hex prefix in msg. Used by translateCommit/translateTag to add
1535	// message-reference edges to the translation DFS so the mapping is
1536	// fully populated by the time the message is rewritten. Ambiguous
1537	// prefixes generate no edge — they cannot be rewritten anyway.
1538	func (t *translator) extractMessageReferences(msg string) []plumbing.Hash {
1539		seen := make(map[plumbing.Hash]struct{})
1540		var out []plumbing.Hash
1541		for _, match := range hashPattern.FindAllString(msg, -1) {
1542			sha1, result := t.resolveMessageRef(match)
1543			if result != matchUnique {
1544				continue
1545			}
1546			if _, dup := seen[sha1]; dup {
1547				continue
1548			}
1549			seen[sha1] = struct{}{}
1550			out = append(out, sha1)
1551		}
1552		return out
1553	}
