1555	// notesCommitTime returns the committer/author timestamp for the
1556	// synthetic notes wrapper commit. Reads SOURCE_DATE_EPOCH (the
1557	// reproducible-builds convention) when set, falling back to the Unix
1558	// epoch so two runs over identical source state always produce the
1559	// same notes-ref hash.
1560	func notesCommitTime() time.Time {
1561		if raw := os.Getenv("SOURCE_DATE_EPOCH"); raw != "" {
1562			if secs, err := strconv.ParseInt(raw, 10, 64); err == nil {
1563				return time.Unix(secs, 0).UTC()
1564			}
1565		}
1566		return time.Unix(0, 0).UTC()
1567	}
