	fmt.Fprintf(out, "fetching %d ref(s) from %s ...\n", len(desired), redactedSourceURL)
	gpDesired := convert.DesiredRefs(desired)
	if err := refService.FetchToStore(ctx, srcRepo.Storer, conn, gpDesired, nil); err != nil &&
