1577	func (t *translator) writeOriginNotes(refName string) (string, error) {
1578		if len(t.commits) == 0 {
1579			return "", nil
1580		}
1581		// Note for each commit: a blob containing the original SHA1 hex + newline.
1582		// We collect (sha256-of-new-commit → blob hash) pairs so the tree entry
1583		// path is the commit's new hash.
1584		type entry struct {
1585			key  plumbing.Hash
