105	// IsRefExcluded reports whether name matches any of the exclude prefixes.
106	// Empty prefixes are ignored. Used to subtract specific namespaces from
107	// auto-discovery (e.g. refs/pull/* under --all-refs against GitHub).
108	func IsRefExcluded(name plumbing.ReferenceName, excludePrefixes []string) bool {
109		if len(excludePrefixes) == 0 {
110			return false
111		}
112		s := name.String()
113		for _, p := range excludePrefixes {
114			p = strings.TrimSpace(p)
115			if p == "" {
116				continue
117			}
118			if strings.HasPrefix(s, p) {
119				return true
120			}
121		}
122		return false
123	}
124	
125	// RefKindFromName infers the ref kind from a fully qualified ref name.
126	// Returns RefKindOther for any refs/* outside refs/heads/ and refs/tags/,
127	// and "" for names that don't start with refs/ at all.
128	func RefKindFromName(name plumbing.ReferenceName) RefKind {
129		switch {
130		case name.IsBranch():
131			return RefKindBranch
132		case name.IsTag():
133			return RefKindTag
134		case strings.HasPrefix(name.String(), "refs/"):
135			return RefKindOther
136		default:
137			return ""
138		}
139	}
140	
141	// ActionForTargetHash returns ActionCreate for zero hashes, ActionUpdate otherwise.
142	func ActionForTargetHash(hash plumbing.Hash) Action {
143		if hash.IsZero() {
144			return ActionCreate
145		}
146		return ActionUpdate
147	}
148	
149	// BranchMapFromRefHashMap extracts short branch names from a ref hash map.
150	func BranchMapFromRefHashMap(refs map[plumbing.ReferenceName]plumbing.Hash) map[string]plumbing.Hash {
151		branches := make(map[string]plumbing.Hash)
152		for name, hash := range refs {
153			if name.IsBranch() {
154				branches[name.Short()] = hash
155			}
156		}
157		return branches
158	}
159	
160	// SelectBranches filters branches to only the requested ones.
161	// If requested is empty, returns all.
162	func SelectBranches(source map[string]plumbing.Hash, requested []string) map[string]plumbing.Hash {
163		if len(requested) == 0 {
164			return source
165		}
166		selected := make(map[string]plumbing.Hash, len(requested))
167		for _, branch := range requested {
168			if hash, ok := source[branch]; ok {
169				selected[branch] = hash
170			}
171		}
172		return selected
173	}
174	
175	// RefPrefixes computes the ref-prefix arguments for v2 ls-refs from cfg.
176	// Under AllRefs the result collapses to a single "refs/" prefix.
177	func RefPrefixes(cfg PlanConfig) []string {
178		if cfg.AllRefs {
179			return []string{"refs/"}
180		}
181		prefixSet := map[string]struct{}{}
182		if len(cfg.Mappings) > 0 {
183			for _, m := range cfg.Mappings {
184				src := strings.TrimSpace(m.Source)
185				switch {
186				case strings.HasPrefix(src, "refs/tags/"):
187					prefixSet["refs/tags/"] = struct{}{}
188				case strings.HasPrefix(src, "refs/heads/"):
189					prefixSet["refs/heads/"] = struct{}{}
190				case !strings.HasPrefix(src, "refs/"):
191					prefixSet["refs/heads/"] = struct{}{}
192				}
193			}
194		} else {
195			prefixSet["refs/heads/"] = struct{}{}
